{"code": "import json
import re
from collections import defaultdict

# Load books data from file
books_file = 'var_functions.query_db:18'
books_path = locals()[books_file]
books_data = json.load(open(books_path))

# Load review data from file
reviews_file = 'var_functions.query_db:20'
reviews_path = locals()[reviews_file]
reviews_data = json.load(open(reviews_path))

print(f"Loaded {len(books_data)} books and {len(reviews_data)} reviews")

# Extract year from details string
def extract_year(details_text):
    # Look for patterns like "January 1, 2004", "May 20, 1996", "2012", etc.
    patterns = [
        r'\b(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+(\d{4})\b',
        r'\b\d{1,2}\s+(January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{4})\b',
        r'\b\d{4}\b'  # Just a 4-digit year
    ]

    for pattern in patterns:
        match = re.search(pattern, details_text)
        if match:
            # Return the year (group 2 for first pattern, group 3 for second, group 0 for third)
            if len(match.groups()) >= 2:
                return int(match.group(2))
            else:
                year = int(match.group(0))
                if 1900 <= year <= 2023:
                    return year
    return None

# Create mapping of book_id to publication year
book_years = {}
for book in books_data:
    book_id = book['book_id']
    year = extract_year(book['details'])
    if year:
        book_years[book_id] = year

print(f"Extracted years for {len(book_years)} books")

# Show some examples
sample_books = list(book_years.items())[:5]
for book_id, year in sample_books:
    print(f"  {book_id}: {year}")"}

