    ]

    for pattern in patterns:
        match = re.search(pattern, details_text)
        if match:
            # Return the year (group 2 for first pattern, group 3 for second, group 0 for third)
            if len(match.groups()) >= 2:
                return int(match.group(2))
            else:
                year = int(match.group(0))
                if 1900 <= year <= 2023:
                    return year
    return None

# Create mapping of book_id to publication year and rating_number
book_info = {}
for book in books_data:
    book_id = book['book_id']
    year = extract_year(book['details'])
    rating_number = int(book['rating_number']) if book['rating_number'] and book['rating_number'].isdigit() else 0
    if year:
        book_info[book_id] = {
            'year': year,
            'decade': (year // 10) * 10,
            'rating_number': rating_number
        }

print(f'Extracted publication years for {len(book_info)} books')

