sample_books = list(book_info.items())[:5]
for book_id, info in sample_books:
    print(f'  {book_id}: {info["year"]} (decade: {info["decade"]}s), ratings: {info["rating_number"]}')

print('\n__RESULT__:')
print(json.dumps({'books_with_years': len(book_info), 'sample': sample_books[:3]}))"}

