    if year:
        book_info[book_id] = {
            'year': year,
            'decade': (year // 10) * 10,
            'rating_number': rating_number
        }

# Load review data
reviews_path = locals()['var_functions.query_db:20']
with open(reviews_path, 'r') as f:
