        if matches:
            for match in matches:
                if isinstance(match, tuple):
                    for element in match:
                        if element.isdigit() and 1900 <= int(element) <= 2023:
                            return int(element)
                elif match.isdigit() and 1900 <= int(match) <= 2023:
                    return int(match)
    return None

